function showModal(linkText = window.location.href) {
  const container = document.querySelector('.preview');
  const modal = document.createElement('div');
  modal.id = 'collab-modal';
  modal.classList.add('collab-modal-overlay');

  const modalContent = document.createElement('div');
  modalContent.classList.add('collab-modal-content');

  modalContent.innerHTML = `
    <p class="collab-modal-title">Copy and share this link if you’d like someone to help fill out the form:</p>
    <div class="collab-link-copy-container">
      <input id="collab-copy-input" type="text" readonly value="${linkText}" />
      <button id="collab-copy-button" class="collab-modal-button">Copy</button>
    </div>
  `;

  modal.appendChild(modalContent);
  container.appendChild(modal);

  const copyButton = document.getElementById('collab-copy-button');
  const copyInput = document.getElementById('collab-copy-input');

  copyButton.addEventListener('click', () => {
  navigator.clipboard.writeText(copyInput.value).then(() => {
    copyButton.textContent = 'Copied!';
    copyButton.style.backgroundColor = 'var(--client-primary-color)'; 
    copyButton.style.color = '#fff'; 

    setTimeout(() => {
      copyButton.textContent = 'Copy';
      copyButton.style.backgroundColor = ''; 
      copyButton.style.color = '#141414'; 
      closeModal();
    }, 500);
  });
});

  

  function closeModal() {
    modal.classList.add('collab-fade-out');
    modal.addEventListener('animationend', () => {
      modal.remove();
    });
  }

  window.addEventListener('click', (event) => {
    if (event.target === modal) {
      closeModal();
    }
  });
}

showModal();

