function preLoads() {
  const cardBody = $(".tab-pane");
  const navItems = $(".nav-tabs > .nav-item");
  const navLinks = $(".nav-tabs > .nav-item > .nav-link");

  $(cardBody[0]).hide().removeClass("active");
  $(cardBody[1]).css("display", "block").addClass("active");
  $(navItems[0]).removeClass("active");
  $(navLinks[0]).removeClass("active");
  $(navItems[1]).addClass("active");
  $(navLinks[1]).addClass("active");
}

const builder = document.querySelector('.builder')

if(!builder){
  preLoads();
}

