function initializeFormAnimations() {
  $('.c-type, .r-type, .sof, .sow').each((_, component) => {
    $(component)
      .find('.form-check, .form-check-inline')
      .addClass('custom-meshid-radio');

    function addSubClassAndType(component, typeArray, className) {
      if ($(component).hasClass(className)) {
        $(component)
          .find('.form-radio .form-check-label')
          .each(function (index) {
            $(this).addClass(
              'sub-type ' + typeArray[index] + ' sub-' + className
            );
          });
      }
    }

    addSubClassAndType(component, cTypes, 'c-type');
    addSubClassAndType(component, rTypes, 'r-type');
    addSubClassAndType(component, sowTypes, 'sow');
    addSubClassAndType(component, sofTypes, 'sof');
  });

  function addRadioTile(component, typeArray) {
    component.each((index, item) => {
      const $item = $(item);
      if (!$item.find('.radio-tile').length) {
        $item.find('.radio-tile').remove();
        $item.append(typeArray[index]);
      }
    });
  }

  addRadioTile($(".sub-sof"), sofTypesElArray);
  addRadioTile($('.sub-sow'), sowTypesElArray);
  addRadioTile($('.sub-c-type'), cTypesArray);
  addRadioTile($('.sub-r-type'), rTypesArray);

  const nameInputs = document.querySelectorAll('.names input');

  nameInputs.forEach((input) => {
    input.addEventListener('input', function () {
      this.value = this.value.charAt(0).toUpperCase() + this.value.slice(1);
    });
  });
}

function setupSignature(signatureKey, customSignSelector) {
  const input = document.querySelector(`.formio-component-${signatureKey} input`);
  if (input) {
    input.addEventListener('input', function () {
      const customSign = document.querySelector(`${customSignSelector} .custom-sign`);
      if (customSign) customSign.innerHTML = this.value;
    });
  }
}

setupSignature('signature', '.formio-component-customSignField');
setupSignature('signature2', '.formio-component-customSignField2');

const builder = document.querySelector('.builder');

if (!builder) {
  // Call the function to set up form animations for the first time
  initializeFormAnimations();

  const cardElement = document.querySelector('.card');

  let lastMutationTime = 0;

  const observer = new MutationObserver((mutationsList, observer) => {
    const currentTime = performance.now();

    for (const mutation of mutationsList) {
      if (currentTime - lastMutationTime > 100) {
        initializeFormAnimations();
      }
      lastMutationTime = currentTime;
    }
  });

  const config = {
    childList: true, // Watch for changes in child elements
    subtree: true, // Watch for changes in descendants
  };

  observer.observe(cardElement, config);

  $('.card')
    .on('input', 'textarea', function () {
      $(this)
        .css('height', 'auto')
        .css('height', this.scrollHeight + 'px');
    })
    .find('textarea');
}

const fontAwesomeSrc = "https://kit.fontawesome.com/7615e5cc93.js";
const izitoastJsSrc = "https://cdn.jsdelivr.net/npm/izitoast@1.4.0/dist/js/iziToast.min.js";
const izitoastCssSrc = "https://cdn.jsdelivr.net/npm/izitoast@1.4.0/dist/css/iziToast.min.css";
const fontAwesomeCssSrc = "https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css";
const remixIconCssSrc = "https://cdnjs.cloudflare.com/ajax/libs/remixicon/3.4.0/remixicon.min.css";
const tingleJsSrc = "https://cdnjs.cloudflare.com/ajax/libs/tingle/0.15.2/tingle.min.js";
const tingleCssSrc = "https://cdnjs.cloudflare.com/ajax/libs/tingle/0.15.2/tingle.min.css";

// Check if FontAwesome is already loaded
if (!document.querySelector('script[src="' + fontAwesomeSrc + '"]')) {
  // Create and append FontAwesome script
  const fontAwesome = document.createElement("script");
  fontAwesome.src = fontAwesomeSrc;
  fontAwesome.crossOrigin = "anonymous";
  fontAwesome.async = true; // Load asynchronously
  document.head.appendChild(fontAwesome);

  // Create and append FontAwesome CSS
  const fontAwesomeCss = document.createElement("link");
  fontAwesomeCss.rel = "stylesheet";
  fontAwesomeCss.href = fontAwesomeCssSrc;
  fontAwesomeCss.crossorigin = "anonymous";
  fontAwesomeCss.referrerpolicy = "no-referrer";
  document.head.appendChild(fontAwesomeCss);

  // Create and append other resources
  const resources = [
    { tag: "link", rel: "stylesheet", href: izitoastCssSrc },
    { tag: "link", rel: "stylesheet", href: remixIconCssSrc },
    { tag: "link", rel: "stylesheet", href: tingleCssSrc },
    { tag: "script", src: izitoastJsSrc, type: "text/javascript", async: true },
    { tag: "script", src: tingleJsSrc, type: "text/javascript", async: true },
  ];

  resources.forEach((resource) => {
    const element = document.createElement(resource.tag);
    Object.assign(element, resource);
    document.head.appendChild(element);
  });
}

function initializeFormFeatures() {

  // Wrap each label with a span element using jQuery
  $(".formio-component > label").each(function () {
    $(this)
      .contents()
      .filter(function () {
        return this.nodeType === 3; // Filter text nodes only
      })
      .wrap("<span></span>");
  });

  updateDescs();


  // $(window).on('resize', updateDescs);

  const $multipleComponent = $(
    ".formio-component-textfield.formio-component-multiple"
  );
  const $formControl = $multipleComponent.find(".form-control");

  if (!$formControl.length) {
    $multipleComponent.find(".formio-button-add-another").click();
  }

  // Tooltip
  $("[data-tooltip]").each(function () {
    const tooltipText = $(this).data("tooltip");
    if (!$(this).find(".custom-tooltip").length) {
      $(this).append(
        `<div class="custom-tooltip"><div class="tooltip-inner">${tooltipText}</div></div>`
      );
    }
  });
}

const componentClasses = [
  ".formio-component-textfield",
  ".formio-component-textarea",
  ".formio-component-number",
  ".formio-component-select",
  ".formio-component-datetime",
  ".formio-component-email"
];

function updateDesc($element) {
  const textWithoutSpaces = $element.text().trim().replace(/\s/g, "");
  const characterCount = textWithoutSpaces.length;
  const hasCustomDesc = $element.parent().parent().find(".custom-desc");



  if (
    $(window).width() <= 730 &&
    characterCount > 40 &&
    hasCustomDesc.length === 0
  ) {
    $element.css("max-width", "100px");
    $element
      .parent()
      .parent()
      .find(".formio-errors")
      .before(
        `<div class="form-text text-muted custom-desc">${$element.text()}</div>`
      );
  } else if (
    $(window).width() <= 600 &&
    characterCount > 30 &&
    hasCustomDesc.length === 0
  ) {
    $element.css("max-width", "100px");
    $element
      .parent()
      .parent()
      .find(".formio-errors")
      .before(
        `<div class="form-text text-muted custom-desc">${$element.text()}</div>`
      );
  } else if (
    $(window).width() <= 500 &&
    characterCount > 20 &&
    hasCustomDesc.length === 0
  ) {
    $element.css("max-width", "100px");
    $element
      .parent()
      .parent()
      .find(".formio-errors")
      .before(
        `<div class="form-text text-muted custom-desc">${$element.text()}</div>`
      );
  } else if (
    $(window).width() <= 450 &&
    characterCount > 15 &&
    hasCustomDesc.length === 0
  ) {
    $element.css("max-width", "100px");
    $element
      .parent()
      .parent()
      .find(".formio-errors")
      .before(
        `<div class="form-text text-muted custom-desc">${$element.text()}</div>`
      );
  }
}

function updateDescs() {
  componentClasses.forEach((classSelector) => {
    const $elements = $(`${classSelector} > label span`);
    $elements.each((index, element) => {
      updateDesc($(element));
    });
  });
}

const builder = document.querySelector(".builder");

if (!builder) {
  const cardElement = document.querySelector(".card");
  let lastMutationTime = 0;

  const observer = new MutationObserver((mutationsList, observer) => {
    const currentTime = performance.now();

    for (const mutation of mutationsList) {
      // Check if the mutation was not triggered by a click event and classList changes
      if (mutation.target.classList.contains("formio-component")) {
        if (currentTime - lastMutationTime > 100) {
          initializeFormFeatures();
        }
        lastMutationTime = currentTime;
      }
    }
  });

  const config = {
    childList: true, 
    subtree: true,
    attributes: true 
  };

  observer.observe(cardElement, config);
}

function sideBar() {
  if ($(".formio-component-tabs > .card .header").length === 0) {
    let headerCode = `<header class="header">
    <div class="switch-holder" style="">
    <input type="checkbox" class="custom-switch" style="">
    <label for="checkbox" class="toggle" style="">
        <div class="bars" id="bar1" style=""></div>
        <div class="bars" id="bar2" style=""></div>
        <div class="bars" id="bar3" style=""></div>
    </label>
  </div>
  </header>`;

    $(".formio-component-tabs > .card").prepend(headerCode);
  }

  $(".card-header .nav-link").each(function () {
    var clonedElement = $(this).clone().removeAttr("href");
    $(this).replaceWith(clonedElement);
  });

  $(".card-header .nav-link").click(function () {
    const clickedIndex = $(this).parent().index();

    $(".card-header .nav-link")
      .removeClass("active")
      .parent()
      .removeClass("active");
    $(this).addClass("active").parent().addClass("active");

    const activeTab = $(".tab-pane.active");
    const targetTab = $(".tab-pane").eq(clickedIndex);

    activeTab.removeClass("active").css("display", "none");
    targetTab.addClass("active").css("display", "block");
  });

  // Call on page load to set the initial state
  $(window).trigger("resize");

  const checkbox = document.querySelector(".card .toggle");

  // Mark the checkbox to indicate the listener is added
  checkbox.addEventListener("click", () => {
    const card = checkbox.closest(".card");
    const sidebar = card.querySelector(".card-header");
    const toggleIcon = card.querySelector(".switch-holder");
    const switchElement = card.querySelector(".custom-switch");
    switchElement.toggleAttribute("checked");
    sidebar.classList.toggle("sidebarshow");
    toggleIcon.classList.toggle("toggled");
  });

  $(".nav-link").hover(
    function () {
      $(this).parent(".nav-item").addClass("hovered");
    },
    function () {
      $(this).parent(".nav-item").removeClass("hovered");
    }
  );
}

function handleSideBar() {
  const handleNavLinkClick = (event) => {
    event.preventDefault();
    const switchElement = document.querySelector(".custom-switch");
    switchElement.removeAttribute("checked");
    document
      .querySelectorAll(".card-header")
      .forEach((cardHeader) => cardHeader.classList.remove("sidebarshow"));
  };

  const handleRes = () => {
    const container = $(".card");
    container.on("click", ".nav-link", handleNavLinkClick);
  };

  handleRes();
}

function updateSidebar() {
  $(".tab-pane").each(function (index) {
    const hasHiddenClass = $(this).children().first().hasClass("formio-hidden");
    const navItem = $(".card-header .nav-item").eq(index);
    const animationOptions = { duration: "fast", easing: "linear" };
    hasHiddenClass
      ? navItem.slideUp(animationOptions)
      : navItem.slideDown(animationOptions);
  });
}

const builder = document.querySelector(".builder");

if (!builder) {
  sideBar();
  handleSideBar();

  const cardElement = document.querySelector(".card");
  let lastMutationTime = 0;

  const observer = new MutationObserver((mutationsList, observer) => {
    const currentTime = performance.now();

    for (const mutation of mutationsList) {
      // Check if the mutation was not triggered by a click event and classList changes
      if (mutation.target.classList.contains("formio-component")) {
        if (currentTime - lastMutationTime > 100) {
          updateSidebar();
        }
        lastMutationTime = currentTime;
      }
    }
  });

  const config = {
    childList: true, 
    subtree: true, 
    attributes: true
  };

  observer.observe(cardElement, config);
}

const builder = document.querySelector(".builder");

if (!builder) {
  // Back Button

  $(".navigation-back > .navigation-back")
    .html('<i class="fa-solid fa-angles-left"></i>')
    .removeClass();

  // Next Button
  $(".navigation-next > .navigation-next")
    .html('<i class="fa-solid fa-angles-right"></i>')
    .removeClass();

  function switchTab(direction) {
    smoothScrollToTop();
    const activeTab = $(".tab-pane.active");
    const targetTab =
      direction === "next"
        ? activeTab
            .nextAll(
              ".tab-pane:not(:has(> .formio-component-fieldset:first-child.formio-hidden))"
            )
            .first()
        : activeTab
            .prevAll(
              ".tab-pane:not(:has(> .formio-component-fieldset:first-child.formio-hidden))"
            )
            .first();

    if (targetTab.length) {
      if (direction === "next") {
        if (!checkError()) {
          showToast();
          smoothScrollToError()
          return false;
        }
      }

      activeTab.removeClass("active").css("display", "none");
      targetTab.addClass("active").css("display", "block");

      const targetIndex = $(".tab-pane").index(targetTab);
      $(".card-header .nav-item")
        .removeClass("active")
        .eq(targetIndex)
        .addClass("active");
      $(".card-header .nav-link")
        .removeClass("active")
        .eq(targetIndex)
        .addClass("active");

      const inputOrTextareaToFocus = $(
        ".tab-pane.active .formio-component-textfield:not(.validated) input, .tab-pane.active .formio-component-number:not(.validated) input, .tab-pane.active .formio-component-email:not(.validated) input, .tab-pane.active .formio-component-textarea:not(.validated) textarea"
      );

      if (
        inputOrTextareaToFocus.length > 0 &&
        !targetTab.hasClass("dark-blur")
      ) {
        inputOrTextareaToFocus.first().focus();
      }
    }
  }

  function handleButtonClick() {

    const isNextButton = $(this).hasClass("navigation-next") || $(this).hasClass("get-started");
    const direction = isNextButton ? "next" : "prev";
  
    switchTab(direction);
  
    if ($(this).hasClass("get-started")) {
      $(this).addClass("hide-this");
    }
  }

  
  $(".navigation-next").on("click", ()=>{
    const $saveButton = $(".tab-pane.active .editgrid-actions .btn-primary");
    if ($saveButton.length) {
      $saveButton.click();
    }
  });
  
  $(".get-started button, .navigation-back, .navigation-next").on("click", handleButtonClick);

  

  function checkError() {
    const requiredElements = $(
      ".tab-pane.active .required:not(.validated):not(.formio-hidden)"
    );

    requiredElements
      .addClass("formio-error-wrapper")
      .find(".form-control")
      .addClass("is-invalid");

    return !requiredElements.length
  }

