  // Function to show the toast notification
  function showToast() {
    const selector = ".tab-pane.active .formio-component-editgrid .editgrid-actions";
    const defaultMessage = "Please fill out all the required fields before proceeding";
    const specificMessage = "Please save all the rows before proceeding";
  
    const showMessage = message => {
      iziToast.warning({
        message,
        messageColor: "#e00303",
        icon: "fa-solid fa-triangle-exclamation",
        iconColor: "#e00303",
        backgroundColor: "#fff",
        position: "bottomCenter",
        displayMode: 1,
        transitionIn: "flipInX",
        transitionOut: "flipOutX",
        progressBarColor: "#e00303",
        close: false,
        closeOnClick: true,
        timeout: 3000,
      });
    };
  
    showMessage($(selector).length > 0 ? specificMessage : defaultMessage);
  }
  

  function smoothScrollToTop() {
    document
      .querySelector(".card")
      .scrollIntoView({
        behavior: "smooth",
        block: "start",
        inline: "nearest",
      });
  }
  function smoothScrollToError() {
    document
      .querySelector(".card")
      .scrollIntoView({
        behavior: "smooth",
        block: "start",
        inline: "nearest",
      });
  }
}

function validateFormInputs() {
  $(".tab-pane").each(function (index) {
    const tabPane = $(this);
    const navItem = tabPane
      .siblings(".card-header")
      .find(".nav-item")
      .eq(index);
    const navLink = navItem.find(".nav-link");
    const requiredComponents = tabPane
      .find(".formio-component.required")
      .not(".formio-hidden");

    if (requiredComponents.length > 0) {
      requiredComponents.each(function () {
        const component = $(this);
        const inputs = component.find(":input");

        const isValid = inputs
          .toArray()
          .some((input) =>
            input.type === "radio" || input.type === "checkbox"
              ? input.checked
              : input.value.trim() !== ""
          );

        if (component.hasClass("formio-component-select")) {
          const hasOptions = component.find("option").length > 0;
          component.toggleClass("validated", hasOptions);
          return;
        }

        const shouldValidateEditGrid =
          component.hasClass("formio-component-editgrid") &&
          component.find('ul li[ref*="editgrid"]').length > 0;

        const shouldValidateSurvey = component.find('input:checked').length == component.find('tbody tr').length;

        const shouldValidate =
          shouldValidateEditGrid ||
          (!component.hasClass("has-error") && isValid);

        if (component.hasClass("formio-component-survey")) {
            component.toggleClass("validated", shouldValidateSurvey);
        } 
        else {
          component.toggleClass("validated", shouldValidate);
        }

      });

      const validatedComponents = tabPane.find(
        ".formio-component.required.validated"
      );

      const remainingCount =
        requiredComponents.length - validatedComponents.length;

      let percentage =
        (validatedComponents.length / requiredComponents.length) * 100;

      percentage = Math.floor(percentage);

      function color(percentage) {
        if (percentage < 33) {
          return "#ff5353";
        }
        if (percentage > 66) {
          return "#28a745";
        } else {
          return "#ffc107";
        }
      }

      const hex = color(percentage);

      tabPane.find(".validation-text").remove();
      navLink.find(".validation-icon").remove();

      if (validatedComponents.length === 0) {
        tabPane.append(
          `<div class="validation-text"><div><i class="fa-solid fa-bookmark"></i>No mandatory fields have yet been completed</div></div>`
        );
        navLink.append(
          `<span class="validation-icon"><i class="fa-solid fa-bookmark"></i></span>`
        );
      } else if (remainingCount === 1) {
        tabPane.append(
          `<div class="validation-text"><div><i class="fa-solid fa-circle-info"></i>There is still 1 mandatory field missing information</div></div>`
        );
        navLink.append(
          `<span class="validation-icon percentage" style="color:${hex}">(${percentage}%)</i></span>`
        );
      } else if (remainingCount > 1) {
        tabPane.append(
          `<div class="validation-text"><div><i class="fa-solid fa-circle-info"></i>There are still ${remainingCount} mandatory fields missing information</div></div>`
        );
        navLink.append(
          `<span class="validation-icon percentage" style="color:${hex}">(${percentage}%)</i></span>`
        );
      } else if (remainingCount === 0) {
        tabPane.append(
          `<div class="validation-text section-completed"><div><i class="fa-solid fa-circle-check"></i>All mandatory fields completed</div></div>`
        );
        navLink.append(
          `<span class="validation-icon"><i class="fa-solid fa-circle-check"></i></span>`
        );
      }
    }
    if (requiredComponents.length === 0 || tabPane.find(".first-page").length) {
      tabPane.find(".validation-text").remove();
      navLink.find(".validation-icon").remove();
      navLink.append(`<span class="validation-icon"></span>`);
    }
  });

  $(".tab-pane.active .validated").removeClass("formio-error-wrapper");
  $(".tab-pane.active .validated .form-control").removeClass("is-invalid");

  $(".formio-component-datagrid").each(function () {
    const table = $(this);
    updateHeaderValidationForAll(table);
  });

  signingPage();

  const totalRequiredElements = $(".required:not(.formio-hidden)").length;
  const validElementsCount = $(
    ".required:not(.validated):not(.formio-hidden)"
  ).length;
  const percentage =
    100 - Math.floor((validElementsCount / totalRequiredElements) * 100);
  const progressBar = `<div class="progress">
  <div
    class="progress-bar"
    role="progressbar"
    style="font-size: 1.5rem; width: ${percentage}%"
    aria-valuemax="100"
  >
    ${percentage}%
  </div>
</div>`
  const progressBarInfo = `<div class="progress progressBarInfo">
  <div
    class="progress-bar"
    role="progressbar"
    style="font-size: 1.2rem; width: 100%"
    aria-valuemax="100"
  >
    This bar will track your form progress...
  </div>
</div>`
;

  if ($(".progress").length) {
    $(".progress").remove();
    $(".card:not(.border)").after(progressBar);
    $(".card:not(.border)").after(progressBarInfo);
  } else {
    $(".card:not(.border)").after(progressBar);
    $(".card:not(.border)").after(progressBarInfo);
  }

  if (percentage > 0) {
    $("button.get-started").text("Continue");
  }
  if (percentage == 100) {
    $("button.get-started").text("Review & Edit");
  }

  checkInputValue();

}

function checkInputValue() {
  $(".formio-component").each(function () {
    const component = $(this);
    const inputs = component.find(":input");
    let isValid;


    if (component.hasClass("formio-component-select")) {
      const hasOptions = component.find("option").length > 0;
      component.toggleClass("has-value", hasOptions);
    } else {
      isValid = inputs
        .toArray()
        .some((input) =>
          input.type === "radio" || input.type === "checkbox"
            ? input.checked
            : input.value.trim() !== ""
        );

        if (component.hasClass("getVal") || component.hasClass("signature-pad")) {
          let timeoutDuration = component.hasClass("getVal") ? 200 : 500;
        
          setTimeout(() => {
            isValid = inputs
              .toArray()
              .some((input) =>
                input.type === "radio" || input.type === "checkbox"
                  ? input.checked
                  : input.value.trim() !== ""
              );
            component.toggleClass("has-value", isValid);
          }, timeoutDuration);
        }

        if (component.hasClass("formio-component-survey") || component.hasClass("signature-pad")) {
          return;
        }

      component.toggleClass("has-value", isValid);

  
      
    }
  });
}

function signingPage() {
  const requiredElements = $(
    ".tab-pane:not(:last) .required:not(.formio-hidden)"
  ).toArray();
  const allValidated = requiredElements.every((element) =>
    $(element).hasClass("validated")
  );

  $(".tab-pane").last().toggleClass("dark-blur", !allValidated);

  if (!allValidated) {
    $(".nav-link").last().find(".validation-icon").remove();
    $(".nav-link")
      .last()
      .append(
        `<span class="validation-icon"><i class="fa-solid fa-lock"></i></span>`
      );
  }

  return allValidated;
}

function updateHeaderValidationForAll() {
  const dataGrids = $(".formio-component-datagrid");

  if ($(".card").find(".formio-component-datagrid").length > 0) {
    dataGrids.each(function () {
      updateValidation($(this));
    });
  }
}

function updateValidation(table) {
  const tbody = table.find("tbody");
  const rows = tbody.find("tr");
  const headerCells = table.find("thead th");

  headerCells.each(function (columnIndex) {
    const isColumnValid = rows.toArray().every(function (row) {
      const td = $(row).find(`td:nth-child(${columnIndex + 1})`);

      if (td.find(".formio-hidden").length !== 0) {
        return true;
      }

      return td.find(".required.validated").length !== 0;
    });

    $(this).toggleClass("validated", isColumnValid);
  });
}

const container = $(".card");

const handleInputChange = (container, selector) => {
  container.on("input change", selector, function () {
    const component = $(this).closest(".formio-component");

    const isValid = component.find(":input").toArray().some(input =>
      (input.type === "radio" || input.type === "checkbox") ? input.checked : input.value.trim() !== ""
    );

    if (component.hasClass("formio-component-survey")) return;

    component.toggleClass("has-value", isValid)
      .removeClass("formio-error-wrapper").find('.form-control').removeClass('is-invalid');  
  });
}

handleInputChange(container, ".formio-component:not(.required) > div > :input");
handleInputChange(container, ".formio-component-selectboxes :input");

container.on("click touch touchend", ".signature-pad", checkInputValue);
container.on("click", ".get-started button", validateFormInputs);


const builder = document.querySelector(".builder");

const cardElement = document.querySelector(".card");

function customDropText() {
  $(".custom-droptext").each(function() { 
    var $currentDropText = $(this); 
    
    if ($currentDropText.find(".is-active").length > 0) {
      var $date = $currentDropText.find('.formio-component-number');
      var $input = $date.find('input');
      
      $date.removeClass('formio-modified validated has-value');
      $input.val('');
    }
  });
}


$(".card").on('change', '.custom-droptext', function() {
  customDropText();
});


if (!builder) {
  validateFormInputs()
  let lastMutationTime = 0;

  const observerCallback = (mutationsList) => {
    const currentTime = performance.now();

    for (const mutation of mutationsList) {
      if (shouldValidateMutation(mutation)) {
        if (currentTime - lastMutationTime > getMutationThreshold(mutation)) {
          validateFormInputs();
        }
        lastMutationTime = currentTime;
      }
    }
  };

  const shouldValidateMutation = (mutation) => {
    return (
      mutation.target.classList.contains("formio-component") ||
      mutation.target.classList.contains("radio-selected") ||
      mutation.type === "childList"
    );
  };

  const getMutationThreshold = (mutation) => {
    return mutation.type === "childList" ? 100 : 10;
  };

  const config = {
    childList: true,
    subtree: true,
    attributes: true,
  };

  const observer = new MutationObserver(observerCallback);
  observer.observe(cardElement, config);
}

function customDatagrid() {
  function initializeCarousel(table) {
    function showColumn(index) {
      const columnHeaders = table.find("th:not(:last-child)");
      const cells = table.find("tbody td:not(:last-child)");

      columnHeaders
        .add(cells)
        .addClass("hidden-column")
        .removeClass("shown-column");

      const headerToShow = columnHeaders.eq(index);
      const cellsToShow = cells.filter(
        (i, el) => i % columnHeaders.length === index
      );

      headerToShow
        .add(cellsToShow)
        .removeClass("hidden-column")
        .addClass("shown-column");
    }

    function navigate(direction) {
      const currentIndex = table.find("th.shown-column").index();
      const numColumns = table.find("th:not(:last-child)").length;
      const newIndex = (currentIndex + direction + numColumns) % numColumns;

      showColumn(newIndex);

      // Add fade-in/fade-out animation
      table.find("th, td").css("opacity", 0).animate({ opacity: 1 }, 500);
    }

    function addNavigationButtons() {
      const buttonsContainer = table.next(".datagrid-buttons");
      buttonsContainer.remove();
      const buttonDiv = $('<div class="datagrid-buttons"></div>');
      const nextButton = $(
        '<button id="nextBtn"><i class="fa-solid fa-circle-right"></i></button>'
      ).click(() => navigate(1));
      const prevButton = $(
        '<button id="prevBtn"><i class="fa-solid fa-circle-left"></i></button>'
      ).click(() => navigate(-1));
      buttonDiv.append(prevButton, nextButton);
      table.after(buttonDiv);
    }

    let currentIndex = table.find("th.shown-column").index();
    if (currentIndex === -1) currentIndex = 0;

    addNavigationButtons();
    showColumn(currentIndex);
  }

  $(".formio-component-datagrid").each(function () {
    const table = $(this);
    initializeCarousel(table);
  });

  

}


function createDynamicTable($datagrid) {
  // Selecting th elements and populating the table header, excluding empty ones
  const thContent = $datagrid
    .find("th")
    .map(function () {
      const thText = $(this).text().trim();
      return thText !== "" ? `<th>${thText}</th>` : "";
    })
    .get();

  // Selecting td elements and populating the table body
  const tdRows = $datagrid
    .find("tbody tr")
    .map(function () {
      const tdContent = $(this)
        .find(
          "td :input:not(button):not(.choices__input--cloned):not(.formio-select-autocomplete-input):not(.flatpickr-input)"
        )
        .map(function () {
          const inputValue = $(this).val();
          let prefix = ''
          let suffix = ''
          if(inputValue){
            prefix = $(this).parent().find('.input-group-prepend .input-group-text').text().trim();
            suffix = $(this).parent().find('.input-group-append .input-group-text').text().trim();
          }
          // Only include non-empty values in the tdContent
          return inputValue == null ? `<td></td>` : `<td>${prefix} ${inputValue} ${suffix}</td>`;
        })
        .get();
      return `<tr>${tdContent.join("")}</tr>`;
    })
    .get();

  // Creating the dynamic table
  const dynamicTable = `
    <table class="table-bordered dynamicTable" border="1">
      <thead>
        <tr><th colspan=${thContent.length}>Full Table Representation</th></tr>
        <tr>${thContent.join("")}</tr>
      </thead>
      <tbody>${tdRows.join("")}</tbody>
    </table>
  `;

  // Checking if there's already a .dynamicTable after .formio-component-datagrid
  const existingDynamicTable = $datagrid
    .next(".datagrid-buttons")
    .next(".dynamicTable");

  // Removing the existing table if it exists
  existingDynamicTable.remove();

  // Inserting the new table after .formio-component-datagrid
  $datagrid.next(".datagrid-buttons").after(dynamicTable);
}

// Iterate over each formio-component-datagrid element
function fullGrid() {
  $(".formio-component-datagrid").each(function () {
    createDynamicTable($(this));
  });
}




const container = $(".card");
container.on("change blur", ".formio-component-datagrid :input", fullGrid);

const builder = document.querySelector(".builder");

if (!builder) {
  customDatagrid();

  const cardElement = document.querySelector(".card");

  const observer = new MutationObserver((mutationsList, observer) => {

    for (const mutation of mutationsList) {
      if (mutation.target.classList.contains("formio-component-datagrid")) {
        customDatagrid();
        fullGrid();
    }
    }
  });

  const config = {
    childList: true,
    subtree: true, 
    attributes: true
  };

  observer.observe(cardElement, config);
}

