function findAndConstructObjects(form, row) {
  let results = {};

  function toPascalCase(label) {
    return label
      .split(' ')
      .map(word => word.charAt(0).toUpperCase() + word.slice(1))
      .join('');
  }

  function getCountryValue(label) {
      const country = countryData.find(c => c.label.trim() === label); 
      return country ? country.value : null;
  }

  function iterate(obj, row) {
    if (obj.hasOwnProperty('tags') && obj.tags.includes('Risk') && !obj.tags.includes('Grid') && Array.isArray(obj.tags) && obj.tags.length > 0) {
      const objectName = obj.label ? toPascalCase(obj.label) : 'UnknownName';

      let value = row[obj.key] || null;
      if (obj.tags.includes('Country') && value) { 
        value = getCountryValue(value); 
      }      

      results[objectName] = {
        value: value,
        indicator: obj.tags[1] || null
      };
    }

    if (obj.tags && Array.isArray(obj.tags) && obj.tags.includes('Grid')) {
      if (obj.components && Array.isArray(obj.components)) {
        obj.components.forEach(component => {
          if (component.tags && component.key) {
            const label = component.key;
    
            // Check row[obj.key] for matching keys
            const rowObjects = row[obj.key];
            if (Array.isArray(rowObjects)) {
              rowObjects.forEach(rowObj => {
                if (label in rowObj) { // Match label with a key in rowObj
                  // Ensure results[objectName] is an array
                  const objectName = component.label ? toPascalCase(component.label) : 'UnknownName';
                  if (!results[objectName]) {
                    results[objectName] = []; // Initialize as an array
                  }
                  results[objectName].push({
                    value: rowObj[label] || null, // Use the value of the matching key
                    indicator: component.tags[1] || null
                  });
                }
              });
            }
          }
        });
      }
      return;
    }
    
       
  
    for (let key in obj) {
      if (typeof obj[key] === 'object' && obj[key] !== null) {
        iterate(obj[key], row);
      }
    }
  }

  iterate(form, row);
  return results;
}

value = findAndConstructObjects(form, row);

