function customSign() {
  let newFont;
  let newFontUrl;
  let addedFontStylesheet = null;
  let handwritingFonts = [];

  // Default font
  const defaultFont = {
    family: 'Dancing Script',
    category: 'handwriting',
  };
  const defaultFontUrl =
    'https://fonts.googleapis.com/css?family=Dancing+Script';

  // Fetch handwriting fonts from Google Fonts API
  $.getJSON(
    'https://www.googleapis.com/webfonts/v1/webfonts?key=AIzaSyAu1p15Q35CQvIWecv5Ox1ykjjRtW1xPCY'
  )
    .done(function (data) {
      handwritingFonts = data.items.filter(
        (font) => font.category === 'handwriting'
      );

      // If no saved font exists, apply default font
      if (!row.hiddenSign) {
        row.hiddenSign = {
          font: defaultFont,
          url: defaultFontUrl,
        };
        applyFontStyle(defaultFont, defaultFontUrl);
      }
    })
    .fail(function (error) {
      console.error('Request failed with error:', error);

      // Fallback to default font even if API fails
      if (!row.hiddenSign) {
        row.hiddenSign = {
          font: defaultFont,
          url: defaultFontUrl,
        };
        applyFontStyle(defaultFont, defaultFontUrl);
      }
    });

  // Function to apply font style
  function applyFontStyle(font, fontUrl) {
    // Remove the previously added font stylesheet, if any

    if (addedFontStylesheet) {
      addedFontStylesheet.remove();
    }

    $('.custom-sign').css('font-family', font.family);

    // Add the new font stylesheet and store the reference
    addedFontStylesheet = $('<link>', {
      href: fontUrl,
      rel: 'stylesheet',
    }).appendTo('head');
  }

  $('.card').on('click', '.generate', function () {
    if (handwritingFonts.length === 0) {
      applyFontStyle(defaultFont, defaultFontUrl);
      return;
    }

    const randomFont =
      handwritingFonts[Math.floor(Math.random() * handwritingFonts.length)];
    newFontUrl = `https://fonts.googleapis.com/css?family=${randomFont.family.replace(
      / /g,
      '+'
    )}`;
    newFont = randomFont;

    row.hiddenSign = {
      font: newFont,
      url: newFontUrl,
    };

    // Call the function to apply font style
    applyFontStyle(newFont, newFontUrl);
  });

  // Apply saved font or default font on initialization
  if (row.hiddenSign) {
    applyFontStyle(row.hiddenSign.font, row.hiddenSign.url);
  } else {
    // Set default font if no saved font exists
    row.hiddenSign = {
      font: defaultFont,
      url: defaultFontUrl,
    };
    applyFontStyle(defaultFont, defaultFontUrl);
  }
}

const builder = document.querySelector('.builder');

if (!builder) {
  const cardElement = document.querySelector('.card');

  customSign();

  let lastMutationTime = 0;

  const observer = new MutationObserver((mutationsList, observer) => {
    const currentTime = performance.now();

    for (const mutation of mutationsList) {
      // Check if the mutation was not triggered by a click event and classList changes
      if (mutation.target.classList.contains('formio-component')) {
        if (currentTime - lastMutationTime > 10) {
          customSign();
        }
        lastMutationTime = currentTime;
      }
    }
  });

  const config = {
    childList: true, // Watch for changes in child elements
    subtree: true, // Watch for changes in descendants
    attributes: true, // Watch for attribute changes
  };

  observer.observe(cardElement, config);
}

