function newRp(form, row) {
  const rpDataArray = [];
  const seen = new Set();
  const stack = [form]; // Use a stack for iterative traversal

  while (stack.length > 0) {
    const obj = stack.pop();

    if (Array.isArray(obj)) {
      stack.push(...obj);
      continue;
    }

    if (
      obj?.tags?.includes('rp') &&
      obj.key &&
      Array.isArray(row[obj.key])
    ) {
      for (const item of row[obj.key]) {
        if (!seen.has(item)) {
          rpDataArray.push({ rpData: item.rpData });
          seen.add(item); // Use Set to prevent duplicates
        }
      }
    }

    for (const key in obj) {
      if (typeof obj[key] === 'object' && obj[key] !== null) {
        stack.push(obj[key]); // Push child objects for processing
      }
    }
  }

  return rpDataArray;
}

value = newRp(form, row);

