function findEVDValues(form, row) {
  const evdValues = new Set();
  const stack = [form];

  while (stack.length > 0) {
    const obj = stack.pop();

    if (Array.isArray(obj)) {
      stack.push(...obj);
      continue;
    }

    const hasEVD = obj?.tags?.includes('EVD');

    if (hasEVD && obj?.key && row?.hasOwnProperty(obj.key)) {
      evdValues.add(row[obj.key]); // Prevent duplicates
    }

    for (const key in obj) {
      if (typeof obj[key] === 'object' && obj[key] !== null) {
        stack.push(obj[key]);
      }
    }
  }

  return [...evdValues]; // Convert Set to array
}

