// 🧩 Question IDs (centralized for easy maintenance)
const QUESTION_IDS = {
  BIR: "376ba5b6-ecc9-4ee2-a153-a3e3b3babe86",
  HRI: "1460a68f-462b-4525-91d2-b6c9db6ca9fa",
