function Dollar(amount, currencyName) {
  var words = [];
  words[0] = 'Zero'; words[1] = 'One'; words[2] = 'Two'; words[3] = 'Three'; words[4] = 'Four';
  words[5] = 'Five'; words[6] = 'Six'; words[7] = 'Seven'; words[8] = 'Eight'; words[9] = 'Nine';
  words[10] = 'Ten'; words[11] = 'Eleven'; words[12] = 'Twelve'; words[13] = 'Thirteen';
  words[14] = 'Fourteen'; words[15] = 'Fifteen'; words[16] = 'Sixteen';
  words[17] = 'Seventeen'; words[18] = 'Eighteen'; words[19] = 'Nineteen';
  words[20] = 'Twenty'; words[30] = 'Thirty'; words[40] = 'Forty';
  words[50] = 'Fifty'; words[60] = 'Sixty'; words[70] = 'Seventy';
  words[80] = 'Eighty'; words[90] = 'Ninety';

  function convertNumber(num) {
    num = parseInt(num);
    if (num === 0) return 'Zero';

    let str = '';

    if (num >= 1000000) {
      str += convertNumber(Math.floor(num / 1000000)) + ' Million ';
      num %= 1000000;
    }
    if (num >= 1000) {
      str += convertNumber(Math.floor(num / 1000)) + ' Thousand ';
      num %= 1000;
    }
    if (num >= 100) {
      str += convertNumber(Math.floor(num / 100)) + ' Hundred ';
      num %= 100;
    }
    if (num > 0) {
      if (num < 20) {
        str += words[num] + ' ';
      } else {
        str += words[Math.floor(num / 10) * 10] + ' ';
        if (num % 10 > 0) {
          str += words[num % 10] + ' ';
        }
      }
    }

    return str.trim();
  }

  amount = amount.toString().replace(/,/g, '');
  let parts = amount.split('.');

  let whole = parts[0];
  let decimal = parts[1] || '0';

  decimal = decimal.padEnd(2, '0').substring(0, 2);

  let words_string = convertNumber(whole) + ' ' + (currencyName || 'Dollars');

  let cents = parseInt(decimal);
  if (cents > 0) {
    let centText = convertNumber(cents);
    words_string += ' and ' + centText + (cents === 1 ? ' Cent' : ' Cents');
  }

  return words_string;
}

