actions.customAction:
 function createRadioTile(className, iconClass, labelText) {
  return `
    <div class="radio-tile">
      <div class="icon ${className}-icon">
        <i class="fa-solid ${iconClass}"></i>
      </div>
      <label for="${className}" class="radio-tile-label">${labelText}</label>
    </div>
  `;
}

// Icons
const employment = createRadioTile(
  'professional',
  'fa-briefcase',
  'Employment'
);
const investmentsSof = createRadioTile(
  'investments',
  'fa-chart-line',
  'Investments'
);
const inheritance = createRadioTile(
  "inheritance",
  "fa-hand-holding-dollar",
  "Gift /Inheritance"
);
const other = createRadioTile('other', 'fa-pen', 'Other');
const sofTypesElArray = [
  employment,
  investmentsSof,
  inheritance,
  other,
];
const sofTypes = [
  "employment-type",
  "investmentsSof-type",
  "inheritance-type",
  "other-type",
];

function initializeFormAnimations() {
  $('.sof').each((_, component) => {
    $(component)
      .find('.form-check, .form-check-inline')
      .addClass('custom-meshid-radio');

    function addSubClassAndType(component, typeArray, className) {
      if ($(component).hasClass(className)) {
        $(component)
          .find('.form-radio .form-check-label')
          .each(function (index) {
            $(this).addClass(
              'sub-type ' + typeArray[index] + ' sub-' + className
            );
          });
      }
    }
    function addRadioTile(component, typeArray) {
      component.each((index, item) => {
        const $item = $(item);
        if (!$item.find('.radio-tile').length) {
          $item.find('.radio-tile').remove();
          $item.append(typeArray[index]);
        }
      });
    }

    addSubClassAndType(component, sofTypes, 'sof');
    addRadioTile($(component).find(".sub-sof"), sofTypesElArray);
  });



  const nameInputs = document.querySelectorAll('.names input');

  nameInputs.forEach((input) => {
    input.addEventListener('input', function () {
      this.value = this.value.charAt(0).toUpperCase() + this.value.slice(1);
    });
  });
}





